// Calculate first day of current month and first day of next month (UTC)
const now = new Date();
const firstOfMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1));
const firstOfNextMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1));

return {
  json: {
    firstOfMonth: String(firstOfMonth.getTime()),
    firstOfNextMonth: String(firstOfNextMonth.getTime()),
    monthName: firstOfMonth.toLocaleString('en-US', { month: 'long', year: 'numeric', timeZone: 'UTC' })
  }
};

const results = $('Fetch Companies Page').first().json.results || [];
const monthName = $('Fetch Renewing Companies').first().json.monthName;

// Parse and sort by renewal date
const companies = results.map(c => {
  const dateStr = c.properties?.contract___renewal_date;
  let d;
  if (/^\d+$/.test(dateStr)) {
    d = new Date(Number(dateStr));
  } else {
    d = new Date(dateStr);
  }
  return {
    id: String(c.id),
    name: c.properties?.name || 'Unknown',
    date: d,
    dateFormatted: d.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric', timeZone: 'UTC' })
  };
}).sort((a, b) => a.date - b.date);

let message = `*:calendar: Renewals for ${monthName}*\n\n`;
message += `*${companies.length} company${companies.length !== 1 ? 'ies' : ''} renewing this month:*\n\n`;

for (const c of companies) {
  message += `\u2022 *${c.name}* \u2014 ${c.dateFormatted} \u2014 <https://app.hubspot.com/contacts/142047914/company/${c.id}|View>\n`;
}

return { json: { message } };
